// Extrair dados básicos do cliente
const nomeCliente = $input.item.json.nomeCliente || "Cliente";
const telefoneCliente = $input.item.json.telefoneCliente || "";
const mensagemCliente = $input.item.json.mensagemCliente || "";

// Exemplo: Simular histórico da conversa (você pode buscar isso de uma planilha)
const historicoConversa = $input.item.json.historico || [];

// Detectar fase com base no histórico ou primeira interação
let fase = "abertura";

if (historicoConversa.length === 1 && historicoConversa[0].includes("Quero saber mais")) {
  fase = "qualificacao";
} else if (mensagemCliente && mensagemCliente.match(/(sim|quero simular|ok)/i)) {
  fase = "oferta personalizada";
} else if (mensagemCliente && mensagemCliente.match(/(preciso pensar|não tenho pressa|já tenho)/i)) {
  fase = "lidar com objeção";
}

// Montar contexto final para o AI Agent
return {
  json: {
    nomeCliente,
    telefoneCliente,
    mensagemCliente,
    beneficioLiquido: null,
    tempoRecebendo: null,
    possuiCredito: null,
    fase,
    memory: historicoConversa.join("\n"),
  },
};
